sp_theme.css_variables:
/* ================================
   POSITIONING + WATER BUBBLE STYLE
   ================================ */

.alert {
    position: fixed !important;
    left: 50% !important;
    transform: translateX(-50%) !important;
    z-index: 99999 !important;
    width: 60% !important;

    background: rgba(255, 255, 255, 0.9);
    backdrop-filter: blur(10px);
    -webkit-backdrop-filter: blur(10px);

    border-radius: 20px;
    padding: 14px 18px;
    font-size: 14px;
    font-weight: 500;
    color: #374151;

    border: 1px solid #e5e7eb;

    display: flex;
    align-items: center;
    gap: 12px;

    box-shadow: 
        0 10px 25px rgba(0,0,0,0.08),
        inset 0 1px 1px rgba(255,255,255,0.6);

    animation: bubbleFloat 0.25s ease;

    max-width: 900px;
}


/* ================================
   REMOVE ONLY BLACK WARNING ICON
   ================================ */

/* Target ONLY ServiceNow default warning icon */
.alert .fa-exclamation-triangle,
.alert .fa-warning {
    display: none !important;
}


/* ================================
   STACKING
   ================================ */

.alert:nth-of-type(1) { top: 70px; }
.alert:nth-of-type(2) { top: 130px; }
.alert:nth-of-type(3) { top: 190px; }
.alert:nth-of-type(4) { top: 250px; }


/* ================================
   ALERT TYPES
   ================================ */

.alert-danger {
    border-left: 3px solid #ef4444;
}

/* ✅ ADDED (no removal) */
.alert-success {
    border-left: 3px solid #22c55e;
}

.alert-warning {
    border-left: 3px solid #f59e0b;
}

.alert-info {
    border-left: 3px solid #3b82f6;
}


/* ================================
   CUSTOM ICON (UPDATED - DYNAMIC)
   ================================ */

.alert:before {
    font-family: "FontAwesome";
    font-size: 14px;
    content: ""; /* ✅ reset default */
}

/* ERROR (existing) */
.alert-danger:before {
    content: "\f071";
    color: #ef4444;
}

/* ✅ ADDED: SUCCESS */
.alert-success:before {
    content: "\f00c";
    color: #22c55e;
}

/* ✅ ADDED: WARNING */
.alert-warning:before {
    content: "\f071";
    color: #f59e0b;
}

/* ✅ ADDED: INFO */
.alert-info:before {
    content: "\f05a";
    color: #3b82f6;
}


/* ================================
   CLOSE BUTTON (UNCHANGED)
   ================================ */

.alert .close,
.alert button.close {
    margin-left: auto;
    font-size: 18px;
    color: #6b7280;
    cursor: pointer;
    background: none;
    border: none;
}

.alert .close:hover {
    color: #111827;
}


/* ================================
   ANIMATION
   ================================ */

@keyframes bubbleFloat {
    from {
        opacity: 0;
        transform: translate(-50%, -10px) scale(0.98);
    }
    to {
        opacity: 1;
        transform: translate(-50%, 0) scale(1);
    }
}

$now-sp-nass-FAB-icon: url('/Incentiqbot_2026.png');

$now-sp-nass-FAB-icon-size-factor: 1.5;

$now-sp-nass-FAB-gradient-hover-color-1: #B2B2B2;
$now-sp-nass-FAB-gradient-hover-color-2: #B2B2B2;

$now-sp-nass-FAB-gradient-active-color-1: #B2B2B2;
$now-sp-nass-FAB-gradient-active-color-2: #B2B2B2;
